ReportUtil = {}

local function getPlayerLevelInterval(player)
    if player.level == 1 then
        return "1"
    elseif player.level == 2 then
        return "2"
    elseif player.level >= 3 and player.level <= 7 then
        return "3_7"
    elseif player.level >= 8 and player.level <= 15 then
        return "8_15"
    elseif player.level >= 16 then
        return "16"
    end
end

local function getPlayerDayPart(player)
    if player.play_days > 30 then
        return "Day30a"
    else
        return "Day" .. player.play_days
    end
end

local function getSuperPlayerPart(player)
    if player.spDays > 0 then
        return "SuperPlayer"
    else
        return "NoSuperPlayer"
    end
end

local function getPlayerSeasonScoreRange(honorId)
    if honorId == 0 then
        return "1000_1099"
    elseif honorId == 1 then
        return "1100_1299"
    elseif honorId == 2 then
        return "1300_1599"
    elseif honorId == 3 then
        return "1600_2099"
    elseif honorId == 4 then
        return "2100"
    else
        return "2100"
    end
end

function ReportUtil.reportDailySignIn(player, id)
    local parts = { "g1046DailySignIn", "PlayerLv" .. player.level, getPlayerDayPart(player), "Id" .. id }
