function ReportUtil.reportSeasonRank(player)
    local seasonInfo = GameSeason.UserSeasonInfoCache[tostring(player.userId)]
    if seasonInfo == nil then
        return
    end

    local manager = GameServer:getRoomManager()
    if not manager:isUserAttrExisted(player.userId) then
        return
    end
    local attr = manager:getUserAttrInfo(player.userId)

    if player.hasReportSeasonRank == false or player.lastReportSeasonRankId == -1 then
        GameAnalytics:design(player.userId, 1, { "Player_RankId", attr.regionId, getPlayerSeasonScoreRange(seasonInfo.honorId) })
        player.hasReportSeasonRank = true
        player.lastReportSeasonRankId = seasonInfo.honorId
        return
    end

    if player.hasReportSeasonRank == true and seasonInfo.honorId ~= player.lastReportSeasonRankId then
        GameAnalytics:design(player.userId, 1, { "Player_RankId", attr.regionId, getPlayerSeasonScoreRange(seasonInfo.honorId) })
        GameAnalytics:design(player.userId, -1, { "Player_RankId", attr.regionId, getPlayerSeasonScoreRange(player.lastReportSeasonRankId) })
        player.lastReportSeasonRankId = seasonInfo.honorId
    end
end

