function ReportUtil.reportNewPlayerHadOpenLicense(player)
    if player.license_isNew == true and player.hadOpenLicense == false then
        player.license_isNew = os.date("%Y-%m-%d")
        GameAnalytics:design(player.userId, 1, { "License_NewOpen", "AllNum" })
    elseif player.license_isNew == true and player.hadOpenLicense == true then
        player.license_isNew = false
        GameAnalytics:design(player.userId, 1, { "License_NewOpen", "AllNum" })
        GameAnalytics:design(player.userId, 1, { "License_NewOpen", "OpenNum" })
    elseif player.license_isNew == os.date("%Y-%m-%d") and player.hadOpenLicense == true then
        player.license_isNew = false
        GameAnalytics:design(player.userId, 1, { "License_NewOpen", "OpenNum" })
    end
end

